// TODO: COMPLETAR - Parse pregunta desde Teams webhook payload
// Espera input como:
// {
//   "text": "¿cuáles son las 5 queries más lentas?",
//   "from": {"id": "user123", "name": "Juan"},
//   "channelData": {"teamsChannelId": "...", "teamsMessageId": "..."},
//   "conversation": {"id": "conv123"}
// }

return {
  pregunta: $input.first().json.text || '',
  user_id: $input.first().json.from?.id || 'unknown',
  session_id: $input.first().json.conversation?.id || 'default',
  conversation_id: $input.first().json.conversation?.id,
  message_id: $input.first().json.channelData?.teamsMessageId,
  channel_id: $input.first().json.channelData?.teamsChannelId,
  from_name: $input.first().json.from?.name
};

// TODO: COMPLETAR - Transformar respuesta a Adaptive Card para Teams
// Espera input como:
// {
//   "respuesta_md": "| query | nombre_corto | ... |",
//   "confidence": 0.95,
//   "fuentes": {"vista_usada": "...", "rows_devueltas": 5},
//   "metadata": {"latencia_ms": 6000}
// }

const response = $input.first().json;
const markdown = response.respuesta_md || 'Sin respuesta';
const confidence = (response.confidence * 100).toFixed(0);
const view = response.fuentes?.vista_usada || 'N/A';
const rows = response.fuentes?.rows_devueltas || 0;
const latency = response.metadata?.latencia_ms || 0;

return {
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "type": "AdaptiveCard",
  "version": "1.4",
  "body": [
    {
      "type": "TextBlock",
      "text": "Respuesta NLQ",
      "weight": "bolder",
      "size": "large"
    },
    {
      "type": "TextBlock",
      "text": markdown,
      "wrap": true,
      "spacing": "medium"
    },
    {
      "type": "TextBlock",
      "text": `[Confianza: ${confidence}%] [Vista: ${view}] [Filas: ${rows}] [Latencia: ${latency}ms]`,
      "size": "small",
      "color": "good",
      "spacing": "small"
    }
  ],
  "actions": [
    {
      "type": "Action.OpenUrl",
      "title": "Util",
      "url": "{{ TODO: WEBHOOK_FEEDBACK_URL?action=helpful&query_id=... }}"
    },
    {
      "type": "Action.OpenUrl",
      "title": "No util",
      "url": "{{ TODO: WEBHOOK_FEEDBACK_URL?action=not_helpful&query_id=... }}"
    }
  ]
};
